mapper.update:
update t_learn_memory
begin_time = #{beginTime}, end_time = #{endTime}, learn_duration = #{learnDuration}, memory_place = #{memoryPlace}, memory_place_detail = #{memoryPlaceDetail}, memory_images = #{memoryImages}, memory_source = #{memorySource}, row_memory_no = #{rowMemoryNo}, learn_type = #{learnType}, learn_content = #{learnContent}, learn_node = #{learnNode}, learn_document = #{learnDocument}, update_time = now(), update_by = #{updateBy}
where id = #{id}

mapper.select:
select t.id, t.memory_no, t.begin_time, t.end_time, t.learn_duration, t.memory_place, t.memory_place_detail, t.memory_images, t.memory_source, t.memory_owner, t.row_memory_no, t.learn_type, t.learn_content, t.learn_node, t.learn_document, t.update_time, t.update_by, i.name as memoryOwnerName from t_learn_memory t left join t_sys_person_info i on i.account_id = t.memory_owner
and t.memory_no like concat('%', #{memoryNo}, '%')
and t.learn_type = #{learnType}
and t.begin_time >= #{beginTime}
and t.begin_time <= #{endTime}
and t.memory_source in
#{item}
and t.memory_owner = #{memoryOwner}
order by t.begin_time desc
